  setInterval(checkTimedBackup,60000);
  if(!window.showDirectoryPicker){showNotice("此瀏覽器不支援 File System Access API，請使用最新版 Chrome 或 Edge。",true);$("chooseFolder").disabled=true;return;}
  try{const handle=await dbGet("root");if(handle&&await verifyPermission(handle,false)){await openRoot(handle)}}catch(e){console.warn(e)}
