  ["search","sourceFilter","spriteFilter","langFilter","categoryFilter","minWidth","maxWidth","minHeight","maxHeight"].forEach(id=>$(id).addEventListener(id==="search"||id.startsWith("min")||id.startsWith("max")?"input":"change",applyFilters));
