async function loadAssetImage(asset,container){try{const h=await resolveFile(asset.relativePath),f=await h.getFile(),url=URL.createObjectURL(f),img=new Image();state.urls.push(url);img.loading="lazy";img.alt=asset.fileName;img.src=url;container.prepend(img)}catch{container.prepend(el("span","","無法載入"))}}
