async function saveCategoryEditor(){const cfg=state.categoryEditor,name=$("categoryName").value.trim();if(!cfg||!name||name.includes(">"))return showNotice("分類名稱不可空白，也不能包含 >。",true);if(cfg.mode==="add-root"){if(Object.prototype.hasOwnProperty.call(CATEGORY_TREE,name))return showNotice("已有同名主分類。",true);CATEGORY_TREE[name]=[]}else if(cfg.mode==="add-child"){const parent=$("categoryParent").value;if(!parent||CATEGORY_TREE[parent].includes(name))return showNotice("請選擇上層分類，且名稱不可重複。",true);CATEGORY_TREE[parent].push(name)}else if(cfg.mode==="rename-root"){if(cfg.parent==="Unknown")return;if(name!==cfg.parent&&Object.prototype.hasOwnProperty.call(CATEGORY_TREE,name))return showNotice("已有同名主分類。",true);const next={};for(const [key,value]of Object.entries(CATEGORY_TREE))next[key===cfg.parent?name:key]=value;CATEGORY_TREE=next;migrateCategoryLabels(cfg.parent,name,true)}else if(cfg.mode==="rename-child"){if(name!==cfg.child&&CATEGORY_TREE[cfg.parent].includes(name))return showNotice("此主分類下已有同名分類。",true);CATEGORY_TREE[cfg.parent]=CATEGORY_TREE[cfg.parent].map(x=>x===cfg.child?name:x);migrateCategoryLabels(`${cfg.parent} > ${cfg.child}`,`${cfg.parent} > ${name}`,false)}state.undo=[];state.redo=[];CATEGORIES=categoryTreeValues();buildCategoryTree();refreshCategoryControls();$("categoryEditorDialog").close();applyFilters();await Promise.all([saveSettings(),saveProject()]);showNotice("分類樹已更新並儲存。")}
