  try{await walkMedia(state.root,"",state.mediaFiles);state.mediaFiles.sort((a,b)=>a.path.localeCompare(b.path,undefined,{numeric:true}));const selectedPaths=new Set(selectedAssets().map(a=>a.relativePath.toLowerCase()));state.mediaFiles.forEach(f=>{if(selectedPaths.has(f.path.toLowerCase()))state.mediaSelected.add(f.path)});$("mediaSearch").value="";renderMediaFiles()}catch(e){$("mediaExportDialog").close();showNotice(`媒體掃描失敗：${e.message}`,true)}
