  $("mediaExportDialog").showModal();$("mediaFileList").textContent="正在準備已選素材…";state.mediaFiles=[];state.mediaSelected.clear();
  try{for(const asset of assets){const handle=await resolveFile(asset.relativePath),ext=fileExtension(asset.fileName);if(MEDIA_EXTS.has(ext))state.mediaFiles.push({name:asset.fileName,path:asset.relativePath,handle,ext})}state.mediaFiles.sort((a,b)=>a.path.localeCompare(b.path,undefined,{numeric:true}));state.mediaFiles.forEach(f=>state.mediaSelected.add(f.path));$("mediaSearch").value="";renderMediaFiles();$("mediaExportSummary").textContent=`已帶入 ${state.mediaFiles.length.toLocaleString()} 個選取素材`}catch(e){$("mediaExportDialog").close();showNotice(`準備匯出失敗：${e.message}`,true)}
